import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import PrivacyNote from "@/components/PrivacyNote";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FormulaBlock from "@/components/FormulaBlock";
import GlossarySection from "@/components/GlossarySection";
import SourceCitations from "@/components/SourceCitations";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) { return formatCurrencyValue(n, { maximumFractionDigits: 0 }); }
function fmt2(n: number) { return formatCurrencyValue(n, { maximumFractionDigits: 2 }); }


const FAQS = [
  { q: "What is included in a monthly mortgage payment?", a: "A standard mortgage payment includes principal (paying down the loan balance), interest (the lender's fee), and often property taxes and homeowners insurance held in escrow. This is sometimes called PITI." },
  { q: "How does the interest rate affect my mortgage payment?", a: "Even a 0.5% difference in rate has a major impact. On a $300,000 30-year loan, the difference between 6% and 6.5% is roughly $100/month - about $36,000 over the life of the loan." },
  { q: "What is the 28% rule for mortgages?", a: "Lenders typically recommend your monthly mortgage payment not exceed 28% of your gross monthly income. For example, a household earning $8,000/month should keep the mortgage payment below $2,240." },
  { q: "Should I choose a 15-year or 30-year mortgage?", a: "A 15-year mortgage has higher monthly payments but builds equity faster and costs significantly less in total interest. A 30-year gives lower payments with more monthly cash flow. Use this calculator to compare both scenarios." },
  { q: "What is PMI (Private Mortgage Insurance)?", a: "PMI is required when your down payment is less than 20% of the home price. It typically costs 0.5-1.5% of the loan amount annually, added to your monthly payment. PMI is cancelled once you reach 20% equity." },
  { q: "How much should I put down on a house?", a: "20% is the traditional benchmark to avoid PMI and get the best rates. However, many programs allow 3-10% down for qualified buyers. A larger down payment reduces your loan principal and monthly payment but requires more upfront savings." },
  { q: "What is an amortization schedule?", a: "An amortization schedule shows how each payment is split between principal and interest over time. In the early years, most of each payment is interest. Over time, more goes to principal. You build equity slowly at first, then faster later." },
  { q: "How do mortgage points work?", a: "One mortgage point = 1% of the loan amount paid upfront to reduce your interest rate by ~0.25%. On a $300,000 loan, one point costs $3,000 and saves ~$50/month. The break-even point is ~5 years, so points make sense if you plan to stay long-term." },
];

export default function MortgageCalculator() {
  useCurrencyVersion();
  const [loanAmount, setLoanAmount] = useState(300000);
  const [interestRate, setInterestRate] = useState(6.5);
  const [loanTermYears, setLoanTermYears] = useState(30);
  const [downPayment, setDownPayment] = useState(60000);

  const principal = loanAmount - downPayment;
  const monthlyRate = interestRate / 100 / 12;
  const numPayments = loanTermYears * 12;
  const monthlyPayment = monthlyRate > 0
    ? (principal * monthlyRate * Math.pow(1 + monthlyRate, numPayments)) / (Math.pow(1 + monthlyRate, numPayments) - 1)
    : principal / numPayments;
  const totalPayment = monthlyPayment * numPayments;
  const totalInterest = totalPayment - principal;
  const downPctg = loanAmount > 0 ? ((downPayment / loanAmount) * 100).toFixed(0) : "0";
  const pmtRequired = downPayment / loanAmount < 0.20;

  const termScenarios = [10, 15, 20, 25, 30].map(y => {
    const months = y * 12;
    const r = interestRate / 100 / 12;
    const pmt = r > 0
      ? (principal * r * Math.pow(1 + r, months)) / (Math.pow(1 + r, months) - 1)
      : principal / months;
    return { y, pmt, totalInt: pmt * months - principal, total: pmt * months };
  });

  return (
    <>
      <SEOHead
        title="Free Mortgage Calculator Online 2025 - Calculate Monthly Payment Instantly | CalcHive"
        description="Free mortgage calculator online. Calculate your exact monthly mortgage payment based on home price, down payment, interest rate and loan term. 100% free for everyone, instant results, no signup required."
        canonical="/mortgage-calculator"
        keywords="free mortgage calculator, mortgage calculator online free, monthly mortgage payment calculator free, home loan calculator free online, mortgage payment estimator free, calculate mortgage payment free, house payment calculator free, mortgage interest calculator free"
        category="Financial Calculators"
        breadcrumbName="Free Mortgage Calculator Online"
        schemaType="WebApplication"
        schemaApplicationCategory="CalculatorApplication"
        faqs={FAQS.slice(0, 3)}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Mortgage Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free mortgage calculator to calculate mortgage payment free from home price, down payment, interest rate, and loan term. This mortgage calculator online free works as a monthly mortgage payment calculator free, home loan calculator free online, mortgage payment estimator free, house payment calculator free, and mortgage interest calculator free for homebuyers.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-6">
          <div className="space-y-6 mb-8">
            <SliderInput id="home-price" label="Home Price" value={loanAmount} min={50000} max={2000000} step={5000} onChange={setLoanAmount} format={fmt} testId="input-home-price" />
            <SliderInput id="down-payment" label="Down Payment" value={downPayment} min={0} max={loanAmount} step={1000} onChange={setDownPayment} format={fmt} testId="input-down-payment" helpText={`${downPctg}% of home price${pmtRequired ? " - PMI likely required" : " - No PMI"}`} />
            <SliderInput id="interest-rate-m" label="Annual Interest Rate" value={interestRate} min={1} max={15} step={0.05} onChange={setInterestRate} format={v => `${v.toFixed(2)}%`} testId="input-interest-rate" />
            <SliderInput id="loan-term" label="Loan Term" value={loanTermYears} min={5} max={30} step={5} onChange={setLoanTermYears} format={v => `${v} years`} testId="input-loan-term" />
          </div>
          <PrivacyNote />
          <motion.div key={`${loanAmount}-${downPayment}-${interestRate}-${loanTermYears}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Payment</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-monthly">{fmt2(monthlyPayment)}</p>
              <p className="text-white/70 text-sm mt-1">on a {fmt(principal)} loan - {interestRate}% for {loanTermYears} years</p>
            </div>
            <div className="grid grid-cols-3 gap-3 mb-3">
              {[
                { label: "Loan Amount", value: fmt(principal) },
                { label: "Total Interest", value: fmt(totalInterest), red: true },
                { label: "Total Cost", value: fmt(totalPayment) },
              ].map(({ label, value, red }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className={`text-lg font-extrabold ${red ? "text-red-600 dark:text-red-400" : "text-foreground"}`}>{value}</p>
                </div>
              ))}
            </div>
            <div className="bg-accent/40 border border-border rounded-xl p-4 text-sm text-muted-foreground">
              28% rule: Recommended gross monthly income = <strong className="text-foreground">{fmt2(monthlyPayment / 0.28)}/month</strong> ({fmt2(monthlyPayment / 0.28 * 12)}/year)
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <FormulaBlock
          formula={[
            "Principal  = Home Price - Down Payment",
            "Monthly Pmt = P  x  [r(1+r)-  x  [(1+r)- - 1]",
            "Total Interest = (Monthly Payment  x  n) - Principal",
          ]}
          legend="r = Monthly Rate (Annual Rate  x  12) - n = Total Payments (Years  x  12) - P = Loan Principal"
          source="Standard amortization formula per SEC & CFPB mortgage modeling guidelines"
          sourceHref="https://www.consumerfinance.gov/ask-cfpb/what-is-amortization-en-1963/"
        />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Monthly Mortgage Payment for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Mortgage payments use the same amortization formula as other loans. Each payment covers both interest (calculated on the remaining principal) and principal repayment. Early payments are mostly interest; later payments shift more toward principal.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Principal = Home Price - Down Payment</p>
            <p>Monthly Payment = P  x  [r(1+r)^n]  x  [(1+r)^n - 1]</p>
            <p className="text-xs text-muted-foreground mt-2">r = Monthly Rate (Annual Rate  x  12) - n = Payments (Years  x  12)</p>
            <p>Total Interest = (Monthly Payment  x  n) - Principal</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How Home Price Down Payment and Interest Rate Affect Your Mortgage</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Term", "Monthly Payment", "Total Interest", "Total Cost", "Interest % of Cost"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {termScenarios.map(({ y, pmt, totalInt, total }) => (
                  <tr key={y} className={`hover:bg-muted/30 ${y === loanTermYears ? "bg-sky-50 dark:bg-sky-950/20 font-semibold" : ""}`}>
                    <td className="py-2.5 px-3 font-semibold text-foreground">{y}-year {y === loanTermYears ? "(current)" : ""}</td>
                    <td className="py-2.5 px-3 text-sky-600 dark:text-sky-400 font-semibold">{fmt2(pmt)}</td>
                    <td className="py-2.5 px-3 text-red-600 dark:text-red-400">{fmt(totalInt)}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{fmt(total)}</td>
                    <td className="py-2.5 px-3 text-muted-foreground">{((totalInt / total) * 100).toFixed(0)}%</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">What is a Good Mortgage Rate in 2025</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Loan Type", "Typical Rate Range", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["30-Year Fixed", "6.5-7.5%", "Most popular mortgage type; stable payments"],
                  ["15-Year Fixed", "5.8-6.8%", "Lower rate, higher payment, less interest overall"],
                  ["5/1 ARM", "5.5-6.5%", "Fixed for 5 years, then adjusts annually"],
                  ["FHA Loan (30-yr)", "6.2-7.2%", "3.5% down; mortgage insurance required"],
                  ["VA Loan (30-yr)", "5.8-6.8%", "0% down; for eligible veterans only"],
                  ["Jumbo Loan (30-yr)", "6.8-7.8%", "For loans above conforming limits (~$766,550)"],
                ].map(([type, rate, notes]) => (
                  <tr key={type} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{type}</td>
                    <td className="py-2.5 px-4 text-sky-600 dark:text-sky-400 font-medium">{rate}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Home Loan Payment Calculator for Every Homebuyer</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free home loan payment calculator to compare monthly payment scenarios and understand affordability before choosing a mortgage.</p>
        </section>

        <GlossarySection headingLevel="h3" terms={[
          { term: "Principal", definition: "The original loan amount - the home price minus your down payment. This is the base amount on which interest is calculated." },
          { term: "Amortization", definition: "The gradual repayment of a loan through scheduled payments. Each payment covers both interest (cost of borrowing) and principal (loan balance reduction)." },
          { term: "APR (Annual Percentage Rate)", definition: "The yearly interest rate charged on your mortgage. For a $300,000 loan at 6.5% APR, the monthly rate is 6.5%  x  12 = 0.542%, applied to the remaining balance each month." },
          { term: "PMI (Private Mortgage Insurance)", definition: "Required when your down payment is less than 20% of the home price. Typically adds 0.5-1.5% of the loan annually to your payment. Cancelled once you reach 20% equity." },
          { term: "28% Rule", definition: "A lender guideline recommending your monthly mortgage payment not exceed 28% of your gross monthly income. Used to assess affordability and loan eligibility." },
          { term: "Down Payment", definition: "The upfront cash you pay toward the home purchase. Reduces your loan principal and monthly payment. A 20% down payment eliminates the need for PMI." },
        ]} />

        <SourceCitations headingLevel="h3" citations={[
          { label: "CFPB - What Is Amortization?", href: "https://www.consumerfinance.gov/ask-cfpb/what-is-amortization-en-1963/", note: "Consumer Financial Protection Bureau mortgage reference" },
          { label: "Investopedia - Mortgage Calculator Guide", href: "https://www.investopedia.com/mortgage-calculator-5084794", note: "Mortgage formula derivation and explanations" },
          { label: "HUD - Homebuyer Education", href: "https://www.hud.gov/topics/buying_a_home", note: "U.S. Department of Housing and Urban Development" },
        ]} />

        <section className="mb-8 mt-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/mortgage-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


